// 사용자 질문 → gemma raw-SQL 요청 본문 (json_schema로 {sql}만 받음)
const q = $json.chatInput || $json.chatMessage || "";
const body = { model:"google/gemma-4-e4b",
  messages:[{role:"system",content:"너는 PostgreSQL 전문가다. jobs 테이블에 대해 사용자 질문을 하나의 SELECT 쿼리로 변환한다.\\n테이블 jobs 컬럼: source(text jumpit|wanted), company(text), title(text), url(text), min_career(int 최소요구연차), max_career(int), tech_stacks(text[] 기술스택배열), locations(text), summary(text 요약/직무내용), status(text done|pending), collected_at(timestamptz), notified_at(timestamptz)\\n규칙:\\n- SELECT 문만 생성(INSERT/UPDATE/DELETE/DROP 등 절대 금지).\\n- 기본적으로 status='done' 조건 포함.\\n- 결과 LIMIT 30 이하.\\n- 직무/키워드/업무내용 검색은 제목과 요약을 모두 본다: (title ILIKE '%키워드%' OR summary ILIKE '%키워드%'). 제목만이 아니라 요약(직무 내용)까지 봐야 관련 직무를 놓치지 않는다.\\n- 특정 기술: EXISTS (SELECT 1 FROM unnest(tech_stacks) s WHERE s ILIKE '%기술%').\\n- 기술 빈도/순위: SELECT unnest(tech_stacks) AS tech, count(*) ... GROUP BY tech ORDER BY count DESC.\\n- \\\"N년 이하\\\": (min_career IS NULL OR min_career<=N). \\\"신입\\\": min_career=0.\\n- 오직 SQL만 출력."},{role:"user",content:q}],
  temperature:0.1, max_tokens:1500,
  response_format:{type:"json_schema", json_schema:{name:"q", schema:{type:"object", additionalProperties:false, properties:{sql:{type:"string"}}, required:["sql"]}}} };
return [{ json: { body } }];

// [2차 방어] gemma가 생성한 SQL 검증. 위반 시 안내 메시지를 반환하는 SELECT로 대체.
let sql = '';
try { sql = JSON.parse($json.choices?.[0]?.message?.content || '{}').sql || ''; } catch (e) {}
sql = String(sql).trim().replace(/;+\s*$/, '');   // 끝 세미콜론 제거

const guide = (msg) => [{ json: { sql: `SELECT '${msg.replace(/'/g, "''")}' AS 안내` } }];

if (!/^\s*SELECT\b/i.test(sql)) return guide('SELECT 쿼리만 실행할 수 있어요.');
if (/\b(INSERT|UPDATE|DELETE|DROP|ALTER|CREATE|GRANT|REVOKE|TRUNCATE|COPY|MERGE)\b/i.test(sql))
  return guide('허용되지 않는 명령이 포함돼 실행하지 않았어요.');
if (/;/.test(sql)) return guide('한 번에 하나의 쿼리만 실행할 수 있어요.');
// LIMIT 강제(없으면 30, 있으면 50 이하로 캡)
if (!/\bLIMIT\s+\d+/i.test(sql)) sql += ' LIMIT 30';
else sql = sql.replace(/\bLIMIT\s+(\d+)/i, (m, n) => 'LIMIT ' + Math.min(Number(n), 50));

return [{ json: { sql } }];

// 결과 모양을 감지해 보기 좋게 포맷: 안내 / 공고목록 / 단일값 / 순위목록 / 표
const rows = $input.all();
const val = (v) => Array.isArray(v) ? v.join(', ') : (v === '' || v == null ? '(미분류)' : v);
let text;

if (rows.length === 0) {
  text = '🔎 결과가 없어요.';
} else {
  const first = rows[0].json;
  const keys = Object.keys(first);

  if ('sql' in first || 'error' in first) {
    text = '⚠️ 쿼리를 실행하지 못했어요. 질문을 조금 다르게 표현해 주세요.';
  } else if (keys.length === 1 && keys[0] === '안내') {
    text = '⚠️ ' + first['안내'];
  } else if ('title' in first) {
    // 공고 목록 카드
    text = `🔎 **${rows.length}건**\n\n`;
    for (const r of rows) {
      const m = r.json;
      const career = [m.min_career, m.max_career].filter(v => v != null).join('~') || '무관';
      const st = Array.isArray(m.tech_stacks) ? m.tech_stacks.filter(Boolean).join(', ') : '';
      text += `**${m.company || ''} — ${m.title}**  ·  경력 ${career}\n${st || '-'}\n${m.url || ''}\n\n`;
    }
  } else if (keys.length === 1) {
    // 단일 값 (count 등)
    text = `🔎 결과: **${val(first[keys[0]])}**`;
  } else {
    // 숫자 컬럼 찾기 → 있으면 순위 목록, 없으면 표
    const numKey = keys.find(k => rows.every(r => typeof r.json[k] === 'number' || /^-?\d+(\.\d+)?$/.test(String(r.json[k]))));
    const labelKey = keys.find(k => k !== numKey);
    if (keys.length === 2 && numKey && labelKey) {
      text = `📊 **${rows.length}개**\n\n`;
      rows.forEach((r, i) => { text += `${i + 1}. **${val(r.json[labelKey])}** — ${r.json[numKey]}\n`; });
    } else {
      // 마크다운 표
      text = `🔎 **${rows.length}행**\n\n| ${keys.join(' | ')} |\n| ${keys.map(() => '---').join(' | ')} |\n`;
      for (const r of rows) text += '| ' + keys.map(k => val(r.json[k])).join(' | ') + ' |\n';
    }
  }
}
return [{ json: { output: text, text } }];
